import{_ as i,o as t,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const l="/images/lekt5601.jpg",a="/images/lekt5602.jpg",s="/images/lekt5603.jpg",k=JSON.parse('{"title":"Lektion 56","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion56.md","filePath":"lektionen/lektion56.md"}'),o={name:"lektionen/lektion56.md"};function u(d,e,h,p,m,b){return t(),r("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-56" tabindex="-1">Lektion 56 <a class="header-anchor" href="#lektion-56" aria-label="Permalink to &quot;Lektion 56&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>56.1. Der reduplizierte Aorist <ul><li>56.1.1. Bildung des Aorist der Kausative und der Wurzeln der 10. Präsensklasse</li></ul></li><li>56.2. Der Injunktiv</li><li>56.3. Der Verbotssatz</li><li>56.4. स्म</li><li>56.5. Übung</li></ul><h2 id="_56-1-der-reduplizierte-aorist" tabindex="-1">56.1. Der reduplizierte Aorist <a class="header-anchor" href="#_56-1-der-reduplizierte-aorist" aria-label="Permalink to &quot;56.1. Der reduplizierte Aorist&quot;">​</a></h2><p>Bildung:</p><p>Augment + reduplizierte Wurzel + a + thematische Sekundärendung</p><p>Die Wurzelsilbe kann tief- oder hochstufig sein. Bei Wurzeln auf -i oder -u ist Tiefstufe die Regel.</p><p>Auslautendes -i, -u wird durch -iy bzw. -uv ersetzt.</p><p>Auslautendes -ā (für -e) fällt ab.</p><p>Paradigma:</p><p>श्रि 1U &quot;sich begeben zu, sich anlehnen&quot;</p><blockquote><table><tbody><tr><td></td><th colspan="2">परस्मैपदम्</th><th colspan="2">आत्मनेपदम्</th></tr><tr><td></td><th>एकवचनम्</th><th>बहुवचनम्</th><th>एकवचनम्</th><th>बहुवचनम्</th></tr><tr><td>**1. तृतीयः**</td><td>अशिश्रियम्<br>(अ-शि-श्रिय्-अम्)</td><td>अशिश्रियाम</td><td>अशिश्रिये</td><td>अशिश्रियामहि</td></tr><tr><td>**2. द्वितीयः**</td><td>अशिश्रियस्</td><td>अशिश्रियत</td><td>अशिश्रियथास्</td><td>अशिश्रियध्वम्</td></tr><tr><td>**3. प्रथमः**</td><td>अशिश्रियत्</td><td>अशिश्रियन्</td><td>अशिश्रियत</td><td>अशिश्रियन्त</td></tr></tbody></table></blockquote><p>Diese Form des Aorist bilden u.a.:</p><ul><li>श्रि 1U &quot;sich begeben zu&quot;</li><li>द्रु 1P &quot;rennen&quot;</li><li>कम् 1Ā &quot;lieben&quot;: अचकमत / अचीकमत (siehe unten!)</li><li>पत् 1P &quot;fallen&quot;: अपप्तत् (a-pa-pt-a-t; pt = Tiefstufe zu pat)</li><li>वच् 2P &quot;sagen&quot;: अवोचत् (a-va + uc-a-t)</li></ul><p>Alle Wurzeln der 10. Präsensklasse sowie alle Kausative bilden stets den reduplizierten Aorist.</p><h3 id="_56-1-1-bildung-des-aorist-der-kausative-und-der-wurzeln-der-10-prasensklasse" tabindex="-1">56.1.1. Bildung des Aorist der Kausative und der Wurzeln der 10. Präsensklasse <a class="header-anchor" href="#_56-1-1-bildung-des-aorist-der-kausative-und-der-wurzeln-der-10-prasensklasse" aria-label="Permalink to &quot;56.1.1. Bildung des Aorist der Kausative und der Wurzeln der 10. Präsensklasse&quot;">​</a></h3><p>Stammsilbe:</p><p>Ausgangspunkt ist die Form des Präsensstamms bzw. des Kausativstamms, die dieser nach Wegfall des Bildungselements -aya- hat (also Stamm auf -p bei Kausativen auf -paya-).</p><p>Der Vokal dieser sog. Stammsilbe bestimmt sich im Aorist nach folgenden Regeln:</p><ul><li>-ā- vor einfachem Konsonanten wird durch -a- ersetzt:<br> पॄ 3P: Kaus. पारयति, Aor. अपिपरत्<br> द्रु 1P: Kaus. द्रावयति, Aor. अदुद्रवत् / अदिद्रवत्<br> नी 1U: Kaus.  नाययति, Aor. अनीनयत्<br> ज्ञा 9U: Kaus. ज्ञापयति, Aor. अजिज्ञपत्</li><li>-ī-, -e-, -ai- vor einfachem Konsonanten wird durch -i- ersetzt:<br> चित् 1P: Kaus. चेतयति, Aor. (Ā) अचीचितत</li><li>-u-, -o-, -au- vor einfachem Konsonanten wird durch -u- ersetzt:<br> चुर् 10U: चोरयति, Aor. अचूचुरत्</li></ul><p>Bei einigen Wurzeln sind die bisher genannten Veränderungen wahlweise bzw. müssen unterbleiben:</p><ul><li>dem auslautenden Konsonanten der Stammsilbe unmittelbar vorangehendes, für ṛ, ṝ, ḷ substituiertes ar, ār, īr, al bleibt wahlweise unverändert oder wird durch ṛ bzw. ḷ ersetzt:<br> कॢप्  1Ā: Kaus. कल्पयति, Aor. अचकल्पत् / अचीकॢपत्<br> कृष् 1P/6U: Kaus. कर्षयति, Aor. अचकर्षत् / अचीकृषत्</li></ul><p>Vokal der Reduplikationssilbe:</p><p>Nachdem die eben genannten Regeln auf die Stammsilbe angewandt sind, müssen folgende Regeln für den Vokal der Reduplikationssilbe befolgt werden:</p><p>Ausgangspunkt ist der reguläre Reduplikationsvokal, d.h.</p><ul><li>a für a, ā, ṛ,  ṝ, ḷ</li><li>i für i, ī, e, ai</li><li>u für u, ū, o, au</li></ul><p>Dieser Reduplikationsvokal unterliegt folgenden Veränderungen:</p><ul><li>i, u wird durch ī, ū ersetzt, wenn die Stammsilbe mit nur einem Konsonanten anfängt und metrisch kurz ist:<br> भिद् 7U: Kaus. भेदयति, Aor. अबीभिदत्<br> तुद् 6U: Kaus. तोदयति, Aor. अतूतुदत्</li><li>a wird durch ī ersetzt, wenn die Stammsilbe metrisch kurz ist und mit nur einem Konsonanten beginnt. Ist die Stammsilbe metrisch kurz und beginnt mit mehr als einem Konsonanten, wird das a der Reduplikationssilbe durch i ersetzt. Ist die Stammsilbe metrisch lang, bleibt das a erhalten:<br> नी 1U: Kaus. नाययति, Stammsilbe des Aor. नय्, Aor. अनीनयत्<br> कृ 8U: Kaus. कारयति, Stammsilbe des Aor. कर्, Aor. अचीकरत्<br> त्यज् 1P: Kaus. त्याजयति, Stammsilbe des Aor. त्यज्, Aor. अतित्यजत्<br> भू 1P: Kaus. भावयति, Stammsilbe des Aor. भव्, Aor. अबीभवत्</li></ul><p>Besonderheiten bestimmter Wurzeln bei Kielhorn, Grammatik § 435c ff.</p><p>Vokalisch anlautende Stammsilben werden nach folgenden Regeln redupliziert:</p><ul><li>Folgt dem anlautenden Vokal nur ein einziger Konsonant oder eine Konsonantengruppe, deren erstes Glied weder Nasal noch d oder r ist, so lautet die reduplizierte Silbe:</li></ul><p>Vokal - erster darauf folgender Konsonant (bzw. dessen in einer Reduplikationssilbe geforderter Vertreter) - i - alle Konsonanten</p><blockquote><p>अश् 9P: Kaus. आशयति, reduplizierte Silbe आशिश्, Aor. आशिशत्<br> इष् 6P: Kaus. एषयति, reduplizierte Silbe एषिष्, Aor. ऐषिषत्<br> ईक्ष् 1Ā: Kaus. ईक्षयति, reduplizierte Silbe ईचिक्ष्, Aor. ऐचिक्षत्</p></blockquote><ul><li>Folgt dem anlautenden Vokal eine mit einem Nasal oder d oder r anfangende Konsonantengruppe, so wird der zweite Konsonant der Gruppe (oder sein Stellvertreter) mit i nach folgendem schema eingeschoben:</li></ul><p>Vokal - erster Konsonant - zweiter Konsonant (Stellvertreter) - i - zweiter Konsonant</p><blockquote><p>अञ्ज् 7P: Kaus. अञ्जयति, reduplizierte Silbe अञ्जिज्, Aor. आञ्जिजत्<br> ऋ 1P: Kaus. अर्पयति, reduplizierte Silbe अर्पिप्, Aor. आर्पिपत्<br> अर्ह् 1P: Kaus. अर्हयति, reduplizierte Silbe अर्जिह्, Aor. आर्जिहत्</p></blockquote><p>Diese Form der Reduplikation vokalisch anlautender abgeleiteter Stämme (Kausative) nennt man &quot;attische Reduplikation&quot;.</p><h2 id="_56-2-der-injunktiv" tabindex="-1">56.2. Der Injunktiv <a class="header-anchor" href="#_56-2-der-injunktiv" aria-label="Permalink to &quot;56.2. Der Injunktiv&quot;">​</a></h2><p>Der Injunktiv ist die augmentlose Form zu Augmentformen, d.h. seine Formen sind identisch mit den augmentlosen Formen des Indikativ Imperfekt oder Aorist. Die einheimische indische Grammatik hat den Injunktiv nicht als besondere grammatische Kategorie erkannt.</p><p>Gemäß der grundlegenden Arbeit:</p><p><img src="'+l+'" alt=""><br> Abb.: Karl Hoffmann (1915 - 1996)<br> Professor für Vergleichende Sprachwissenschaft, Universität Erlangen-Nürnberg (1955 - 1983)<br> [Bildquelle: <a href="http://titus.uni-frankfurt.de/personal/galeria/hoffma-k.htm" target="_blank" rel="noreferrer">http://titus.uni-frankfurt.de/personal/galeria/hoffma-k.htm</a>. -- Zugriff am 2009-02-27]</p><blockquote><p>Hoffmann, Karl &lt;1915 - 1996&gt;: Der Injunktiv im Veda : eine synchronische Funktionsuntersuchung / von Karl Hoffmann. -- Heidelberg : Winter, 1967. -- 298 S. -- (Indogermanische Bibliothek : 3. Reihe, Untersuchungen)</p></blockquote><p>hat der Injunktiv im Veda folgende Eigenschaften:</p><ul><li>er ist nicht berichtend, sondern erwähnend</li><li>er ist zeitstufenlos</li><li>der Injunktiv Präsens (= augmentloses Imperfekt) bezeichnet den unvollendeten Aspekt</li><li>der Injunktiv Aorist bezeichnet den vollendeten Aspekt.</li></ul><p>Im nachvedischen Sanskrit kommt der Injunktiv nur noch in Verbindung mit der Verbotspartikel मा (+ Injunktiv Aorist) bzw. मा स्म (+ Injunktiv Präsens oder Aorist) vor, der unterschiedliche Aspekt kommt meist nicht mehr zum Tragen.</p><p>(mit Aspekt</p><ul><li>würde मा + Injunktiv Aorist einen Prohibitivsatz bezeichnen: &quot;Beginne nicht zu ...!&quot;, &quot;Tu nicht ...!&quot;</li><li>würde मा स्म + Injunktiv Präsens einen Inhibitivsatz bezeichnen, d.h. eine schon verlaufende Handlung oder ein schon bestehender Zustand wird verboten: &quot;Höre auf, zu ...!&quot;, &quot;Lass ab von ...!&quot;</li></ul><p>Dieser Unterschied wird jedoch im klassischen Sanskrit meist nicht gemacht.)</p><h2 id="_56-3-der-verbotssatz" tabindex="-1">56.3. Der Verbotssatz <a class="header-anchor" href="#_56-3-der-verbotssatz" aria-label="Permalink to &quot;56.3. Der Verbotssatz&quot;">​</a></h2><p>Hauptform:</p><p>मा + Injunktiv Aorist</p><p>मा स्म + Injunktiv Aorist oder Injunktiv Präsens</p><p>Beispiele:</p><blockquote><p>मा कर्महेतुर्भूः &quot;Werde nicht einer, der durch die Frucht einer Tat motiviert wird!&quot; (Injunktiv Aorist) (भगवद्गीता 2,47c)</p><p>क्लैब्यं मा स्म गमः &quot;Werde nicht unmännlich!&quot; (Injunktiv Aorist) (भगवद्गीता 2,3a)</p></blockquote><p><img src="'+a+'" alt=""><br> Abb.: क्लैब्यं मा स्म गमः (भगवद्गीता 2,3a)<br> Poster (Ernesto Che Guevara) einer politischen Partei in Vallachira (വാല്ലചിര), Thrissur (തൃശ്ശൂര്‍).<br> &quot;Rough translation of what is written on it would be:<br> Martyrdom is a fascinating experience for a revolutionary.<br> And a daunting resort to a dastard.<br> Che is not a role model for cowards.&quot;<br> [Bildquelle: Hari_Menon. -- <a href="http://www.flickr.com/photos/me_haridas/2282563515/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/me_haridas/2282563515/</a>. -- Zugriff am 2009-02-27. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>Beide Beispiele haben prohibitiven Sinn. Der Injunktiv Aorist ist hier also in seiner ursprünglichen Bedeutung gebraucht. (Das Überwiegen des Injunktiv Aorist in solchen Sätzen erklärt sich vielleicht aus dem Überwiegen der Prohibitivsätze gegenüber Inhibitivsätzen, doch müsste diese Frage für das klassische Sanskrit noch untersucht werden.)</p><p>Andere Formen von Verbotssätzen:</p><ul><li>मा + (स्म) + Imperativ (selten)<br> z.B.  मा ते सङ्गो ऽस्त्वकर्मणि</li><li>अलम् oder कृतम्  = Instrumentalis im Inhibitivsatz<br> z.B. अलं  विषादेन &quot;Genug mit dem Verzagen! = Hör auf, verzagt zu sein! = Kopf hoch!&quot;</li><li>न + Gerundiv (Partizip der Notwendigkeit)</li></ul><p>Daneben gibt es noch weitere, seltenere Formen von Verbotssätzen, siehe z.B.</p><blockquote><p>Speyer, Jacob S. (Jacob Samuel) &lt;1849-1913&gt;: Sanskrit sytax. -- Leyden : Brill, 1886. -- § 353.</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.:  अलं  विषादेन<br> [Bildquelle: World Bank / Curt Carnemark. -- <a href="http://www.flickr.com/photos/worldbank/2244549274/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldbank/2244549274/</a>. -- Zugriff am 2009-02-27. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_56-4-स्म" tabindex="-1">56.4. स्म <a class="header-anchor" href="#_56-4-स्म" aria-label="Permalink to &quot;56.4. स्म&quot;">​</a></h2><p>स्म hebt hervor: &quot;wahrlich, allerdings, gewiss, gerade&quot;</p><p>Außerdem ist folgende Konstruktion sehr wichtig:</p><blockquote><p>स्म + Indikativ Präsens dient zum Erzählen in der Vergangenheit, vor allem um eine Dauer in der Vergangenheit zu bezeichnen:</p><p>z.B. वसति स्म &quot;es wohnte einmal&quot; (स्म kann manchmal auch fehlen).</p></blockquote><h2 id="_56-5-ubung" tabindex="-1">56.5. Übung <a class="header-anchor" href="#_56-5-ubung" aria-label="Permalink to &quot;56.5. Übung&quot;">​</a></h2><p>A) Bestimmen und übersetzen Sie ohne Hilfsmittel (!) folgende Formen:</p><ol><li>अस्मत्</li><li>अस्मात्</li><li>दध्यौ</li><li>लिल्यिरे</li><li>अगामि</li><li>आगामी</li><li>अक्लिद्यत्</li><li>अक्लिदत्</li><li>अचिक्लिदत्</li><li>स्त्रीघ्नाय</li><li>नेद</li><li>प्लवमान</li><li>अकारि</li><li>अद्य</li><li>अतन्द्रिते</li><li>अन्तरे</li><li>महीक्षितम्</li><li>आर्दिधाम</li><li>आसम्</li><li>आसाम्</li><li>आसि</li><li>अनूनुदत्</li><li>जिघ्रति</li><li>जाग्रति</li><li>आस्थत्</li><li>आस्थात्</li><li>अबीभषम्</li><li>अशुषः</li><li>कपी</li><li>आततायी</li><li>महती</li><li>इतरेतरेषाम्</li><li>धेक्षि</li><li>अश्यन्</li><li>कन्ये</li><li>सौमि</li><li>आर्पिपन्</li><li>परिव्राट्</li><li>जेरिम</li><li>अततर्पत</li><li>तत्रिरे</li><li>मात्रीकुरु</li><li>आनीः</li><li>मानुषाभ्याम्</li><li>अजिघ्रपम्</li><li>रते</li><li>जातु</li><li>जाती</li><li>जाता</li><li>अपरस्मै</li><li>अदीपि</li><li>अजूजुषाम</li><li>नवानाम्</li><li>अश्रुणोः</li><li>पृथक्पृथक्</li><li>असिष्णिहम्</li><li>मन्मय्यः</li><li>औजिहः</li><li>अशिनट्</li><li>पाप्यभूवन्</li><li>शोत्स्यामः</li><li>अदीर्यथाः</li><li>भस्मसात्संपेदे</li><li>नवधा</li><li>अविनक्</li><li>आन</li><li>शान्तयोः</li><li>वारीणि</li><li>वारिणी</li><li>वारिणि</li><li>अद्भिः</li><li>अदिध्मपन्</li><li>अववर्जन्</li><li>शितवत्यौ</li><li>अहो</li><li>एकशः</li><li>अपप्तः</li><li>अकस्मात्</li><li>मित्रध्रुक्</li><li>अवोचन्</li></ol>',69)])])}const g=i(o,[["render",u]]);export{k as __pageData,g as default};
